import{_ as t,o as a,c as r,ag as o}from"./chunks/framework.BBkp40gP.js";const g=JSON.parse('{"title":"For Players","description":"","frontmatter":{},"headers":[],"relativePath":"for-players.md","filePath":"for-players.md"}'),i={name:"for-players.md"};function n(l,e,s,h,c,p){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="for-players" tabindex="-1">For Players <a class="header-anchor" href="#for-players" aria-label="Permalink to &quot;For Players&quot;">​</a></h1><p>A quick orientation for anyone jumping into a pack that includes Nostalgic Trees.</p><h2 id="the-core-loop" tabindex="-1">The core loop <a class="header-anchor" href="#the-core-loop" aria-label="Permalink to &quot;The core loop&quot;">​</a></h2><ol><li>Craft a <strong>Dirt Sapling</strong> from 8 dirt and an oak sapling.</li><li>Plant, wait for it to grow, chop the log with a <strong>Mallet</strong> — you get a <strong>Stripped Log</strong>.</li><li>Craft the stripped log into a <strong>Chunk</strong>, and combine 4 chunks + 4 apples + 1 honeycomb in a crafting table to produce the tree&#39;s output item.</li><li>Use that output to craft higher-tier saplings, or combine multiple saplings through mutation to unlock new trees.</li></ol><h2 id="mallets" tabindex="-1">Mallets <a class="header-anchor" href="#mallets" aria-label="Permalink to &quot;Mallets&quot;">​</a></h2><p>Break resource logs with a mallet to get stripped logs. Using a bare hand or an axe gives nothing useful — the mallet is mandatory.</p><p>Mallet tiers affect durability cost. A netherite mallet on a dirt tree uses less durability than a wooden mallet on the same tree. Match your mallet tier to the trees you&#39;re harvesting.</p><h2 id="mutations" tabindex="-1">Mutations <a class="header-anchor" href="#mutations" aria-label="Permalink to &quot;Mutations&quot;">​</a></h2><p>Some trees can only be obtained by mutating another tree into them. The process:</p><ol><li>Plant the required <strong>base sapling</strong> on dirt or grass.</li><li>Right-click the sapling with each required <strong>honeycomb</strong> in the recipe.</li><li>If the recipe has a <strong>catalyst</strong>, right-click with the catalyst item to consume it.</li><li>Place an <strong>Advanced Beehive</strong> nearby with bees inside.</li><li>Wait. Bees pollinate the sapling, and after the required number of cycles, it transforms into the mutated sapling.</li></ol><p>Mutation progress is shown in the <strong>Jade</strong> tooltip when looking at the sapling.</p><h2 id="drying-rack" tabindex="-1">Drying Rack <a class="header-anchor" href="#drying-rack" aria-label="Permalink to &quot;Drying Rack&quot;">​</a></h2><p>Place a drying rack and right-click with a valid item to begin drying. After the drying time completes, the item transforms into its result.</p><p>Default recipes:</p><ul><li>Dirt Sapling → Stone Sapling</li><li>Clay Ball → Bone Meal</li><li>Bone Block → Snow Block</li></ul><p>Drying recipes are visible in JEI.</p><h2 id="advanced-beehive" tabindex="-1">Advanced Beehive <a class="header-anchor" href="#advanced-beehive" aria-label="Permalink to &quot;Advanced Beehive&quot;">​</a></h2><p>Holds up to 5 bees. When bees return from a resource tree, they produce that tree&#39;s specific honeycomb. Use honeycombs in mutation recipes and resource crafts.</p>',18)])])}const u=t(i,[["render",n]]);export{g as __pageData,u as default};
